<?php
 namespace WPAICG\Core\Providers\Azure\Methods; use WPAICG\Core\Providers\AzureProviderStrategy; if (!defined('ABSPATH')) { exit; } function get_api_headers_logic(AzureProviderStrategy $strategyInstance, string $api_key, string $operation): array { $headers = [ 'Content-Type' => 'application/json', 'api-key' => $api_key, ]; if ($operation === 'stream') { $headers['Accept'] = 'text/event-stream'; $headers['Cache-Control'] = 'no-cache'; } return $headers; }